const addToCart = (productId) => {
  const inCart = cartProducts.find(p => p.id === productId);
  if (!inCart) {
    setCartProducts([...cartProducts, { id: productId, qty: 1 }]);
  } else {
    setCartProducts(cartProducts.map(p =>
      p.id === productId ? { ...p, qty: p.qty + 1 } : p
    ));
  }
};
